mapper.update:
MERGE INTO t_mex_scm_invoice t USING (
SELECT #{r.wms_key} AS wms_key, #{r.date} AS invoice_create, #{r.invoice_no} AS invoice_no, #{r.itemcode} AS itemcode FROM dual
) s ON ( t.invoice_create = s.invoice_create AND t.invoice_no = s.invoice_no AND t.itemcode = s.itemcode ) WHEN MATCHED THEN UPDATE SET t.wms_key = s.wms_key

		update t_mex_scm_invoice t
		set t.wms_key = #{wms_key}
        where t.invoice_create = #{date}
          and t.invoice_no = #{invoice_no}
